{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));
    //
    // Check the 4KB granularity.
    //
    ASSERT(((configParams->startAddr & 0xFFFU) == 0U) &&
           ((configParams->endAddr   & 0xFFFU) == 0xFFFU));

    //
    // Configure the start and end addresses of the MPU region.
    //
    HWREG(base + SYNCBRIDGEMPU_O_MPUR_START((uint32_t)region)) =
                                                configParams->startAddr;
    HWREG(base + SYNCBRIDGEMPU_O_MPUR_END((uint32_t)region))   =
                                                configParams->endAddr;

    //
    // Configure the type of accesses allowed in the MPU region.
    //
    HWREGB(base + SYNCBRIDGEMPU_O_MPUR_ACCESS((uint32_t)region)) =
                                        (uint8_t)configParams->accessPermission;
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    //
    // Set the MPU function enable bit.
    //
    HWREGB(base + SYNCBRIDGEMPU_O_MPUCTRL) |= SYNCBRIDGEMPU_MPUCTRL_MPUEN;
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    //
    // Clear the MPU function enable bit.
    //
    HWREGB(base + SYNCBRIDGEMPU_O_MPUCTRL) &= (uint8_t)(~SYNCBRIDGEMPU_MPUCTRL_MPUEN);
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    //
    // Lock the MPU configuration.
    //
    HWREGB(base + SYNCBRIDGEMPU_O_MPUCFG_LOCK) = SYNCBRIDGEMPU_MPUCFG_LOCK_LOCK;
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    //
    // Unlock the MPU configuration.
    //
    HWREGB(base + SYNCBRIDGEMPU_O_MPUCFG_LOCK) = 0U;
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    //
    // Commit the lock on the MPU configuration.
    //
    HWREGB(base + SYNCBRIDGEMPU_O_MPUCFG_COMMIT) = SYNCBRIDGEMPU_MPUCFG_COMMIT_COMMIT;
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    uint8_t i;

    for (i = 0U; i < (uint8_t)SYNCBRIDGEMPU_TOTAL_MPU; i++)
    {
        //
        // Lock the MPU region configuration.
        //
        HWREGB(base + SYNCBRIDGEMPU_O_MPUR_LOCK(i)) = 1U;
    }
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    uint8_t i;

    for (i = 0U; i < (uint8_t)SYNCBRIDGEMPU_TOTAL_MPU; i++)
    {
        //
        // Unlock the MPU region configuration.
        //
        HWREGB(base + SYNCBRIDGEMPU_O_MPUR_LOCK(i)) = 0U;
    }
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    uint8_t i;

    for (i = 0U; i < (uint8_t)SYNCBRIDGEMPU_TOTAL_MPU; i++)
    {
        //
        // Commit the lock on the MPU region registers.
        //
        HWREGB(base + SYNCBRIDGEMPU_O_MPUR_COMMIT(i)) = 1U;
    }
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    //
    // Lock the MPU region registers.
    //
    HWREGB(base + SYNCBRIDGEMPU_O_MPUR_LOCK((uint32_t)region)) = 1U;
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    //
    // Unlock the MPU region registers.
    //
    HWREGB(base + SYNCBRIDGEMPU_O_MPUR_LOCK((uint32_t)region)) = 0U;
}

{
    //
    // Check the arguments.
    //
    ASSERT(SYNCBRIDGEMPU_isBaseValid(base));

    //
    // Commit the lock on MPU region registers.
    //
    HWREGB(base + SYNCBRIDGEMPU_O_MPUR_COMMIT((uint32_t)region)) = 1U;
}
